import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { handleError, handleSuccess } from '../utils';

import Sidebar from '../components/common/Sidebar';
import Topbar from '../components/common/Topbar';
import Icon from '../components/common/Icons';

function SalesInvoice({ theme = 'light', onToggleTheme }) {
    const navigate = useNavigate();
    const [parties, setParties] = useState([]);
    const [products, setProducts] = useState([]);
    const [invoiceNo, setInvoiceNo] = useState('1');
    const [invoiceDate, setInvoiceDate] = useState(new Date().toISOString().split('T')[0]);
    const [selectedParty, setSelectedParty] = useState('');
    const [selectedPartyName, setSelectedPartyName] = useState('');
    const [items, setItems] = useState([{ name: '', quantity: '', rate: '', discountPercent: '', discountAmount: '', amount: 0, productId: '' }]);
    const [notes, setNotes] = useState('');
    const [paymentMode, setPaymentMode] = useState('Cash');




    async function fetchParties() {
        try {
            const response = await fetch("http://localhost:8000/parties", {
                headers: { 'Authorization': localStorage.getItem('token') }
            });
            const result = await response.json();
            if (result.success) setParties(result.parties);
        } catch { handleError('Failed to load parties'); }
    };

    async function fetchProducts() {
        try {
            const response = await fetch("http://localhost:8000/products", {
                headers: { 'Authorization': localStorage.getItem('token') }
            });
            const result = await response.json();
            if (result) setProducts(result);
        } catch { handleError('Failed to load products'); }
    };

    async function fetchLastInvoiceNo() {
        try {
            const response = await fetch("http://localhost:8000/invoices", {
                headers: { 'Authorization': localStorage.getItem('token') }
            });
            const result = await response.json();
            if (result.success && result.invoices.length > 0) {
                const lastNo = parseInt(result.invoices[0].invoiceNo);
                setInvoiceNo((lastNo + 1).toString());
            }
        } catch { /* ignore */ }
    }

    useEffect(() => {
        fetchParties();
        fetchProducts();
        fetchLastInvoiceNo();
    }, []);

    const handleAddItem = () => {
        setItems([...items, { name: '', quantity: '', rate: '', discountPercent: '', discountAmount: '', amount: 0, productId: '' }]);
    };

    const handleRemoveItem = (index) => {
        if (items.length > 1) {
            const newItems = items.filter((_, i) => i !== index);
            setItems(newItems);
        }
    };

    const handleItemChange = (index, field, value) => {
        const newItems = [...items];

        if (field === 'name') {
            const product = products.find(p => p.name === value);
            if (product) {
                newItems[index].productId = product._id;
                newItems[index].rate = product.unitPrice;
                newItems[index].name = product.name;
            } else {
                newItems[index].name = value;
            }
        } else {
            newItems[index][field] = value;
        }

        // Calculate amount
        const qty = parseFloat(newItems[index].quantity) || 0;
        const rate = parseFloat(newItems[index].rate) || 0;
        const discPercent = parseFloat(newItems[index].discountPercent) || 0;
        let discAmount = parseFloat(newItems[index].discountAmount) || 0;

        if (field === 'discountPercent') {
            discAmount = (qty * rate * discPercent) / 100;
            newItems[index].discountAmount = discAmount.toFixed(2);
        } else if (field === 'discountAmount') {
            newItems[index].discountPercent = ((discAmount / (qty * rate)) * 100).toFixed(2);
        }

        newItems[index].amount = (qty * rate) - discAmount;
        setItems(newItems);
    };

    const subTotal = items.reduce((acc, item) => acc + (item.amount || 0), 0);
    const totalAmount = subTotal;

    const handleSaveInvoice = async (saveAndNew = false) => {
        if (!selectedParty) return handleError('Please select a party');
        if (items.some(item => !item.name || !item.quantity || !item.rate)) return handleError('Please fill all item details');

        const invoiceData = {
            partyId: selectedParty,
            partyName: selectedPartyName,
            invoiceNo,
            invoiceDate,
            items: items.map(item => ({
                ...item,
                quantity: Number(item.quantity),
                rate: Number(item.rate),
                discountPercent: Number(item.discountPercent) || 0,
                discountAmount: Number(item.discountAmount) || 0
            })),
            subTotal,
            totalAmount,
            notes,
            paymentMode,
            businessName: localStorage.getItem('businessName') || 'SmartStock Inc.'
        };

        try {
            const response = await fetch("http://localhost:8000/invoices", {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': localStorage.getItem('token')
                },
                body: JSON.stringify(invoiceData)
            });
            const result = await response.json();
            if (result.success) {
                handleSuccess('Invoice saved successfully');
                if (saveAndNew) {
                    setSelectedParty('');
                    setSelectedPartyName('');
                    setItems([{ name: '', quantity: '', rate: '', discountPercent: '', discountAmount: '', amount: 0, productId: '' }]);
                    setInvoiceNo((parseInt(invoiceNo) + 1).toString());
                } else {
                    navigate(`/sales/preview/${result.invoice._id}`);
                }
            } else {
                handleError(result.message);
            }
        } catch { handleError('Failed to save invoice'); }
    };

    return (
        <div className="ss-layout">
            <Sidebar activeSection="sales" />

            <div className="ss-main">
                <Topbar 
                    title="Create Sales Invoice" 
                    onToggleTheme={onToggleTheme}
                    isDark={theme === 'dark'}
                    backAction={() => navigate(-1)}
                />

                <div className="ss-content">

            <div className="ss-invoice-card">
                <div className="ss-invoice-grid">
                    <div className="ss-invoice-field">
                        <label>Select Party</label>
                        <select 
                            className="ss-invoice-select"
                            value={selectedParty}
                            onChange={(e) => {
                                setSelectedParty(e.target.value);
                                const p = parties.find(party => party._id === e.target.value);
                                setSelectedPartyName(p ? p.name : '');
                            }}
                        >
                            <option value="">Search for party</option>
                            {parties.map(party => (
                                <option key={party._id} value={party._id}>{party.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="ss-invoice-field">
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <label>Invoice No</label>
                        </div>
                        <input 
                            className="ss-invoice-input"
                            value={invoiceNo}
                            onChange={(e) => setInvoiceNo(e.target.value)}
                        />
                    </div>

                    <div className="ss-invoice-field">
                        <label>Invoice Date</label>
                        <input 
                            type="date"
                            className="ss-invoice-input"
                            value={invoiceDate}
                            onChange={(e) => setInvoiceDate(e.target.value)}
                        />
                    </div>
                </div>

                <div className="ss-billing-table-wrap">
                    <table className="ss-billing-table">
                        <thead>
                            <tr>
                                <th style={{ width: '60px' }}>S.N.</th>
                                <th>Name</th>
                                <th style={{ width: '120px' }}>Quantity</th>
                                <th style={{ width: '140px' }}>Rate</th>
                                <th style={{ width: '180px' }}>Discount</th>
                                <th style={{ width: '140px' }}>Amount</th>
                                <th style={{ width: '40px' }}></th>
                            </tr>
                        </thead>
                        <tbody>
                            {items.map((item, index) => (
                                <tr key={index}>
                                    <td style={{ color: 'var(--text-muted)', fontWeight: 600 }}>{index + 1}</td>
                                    <td>
                                        <select 
                                            className="ss-billing-item-input"
                                            style={{ fontWeight: 600 }}
                                            value={item.name}
                                            onChange={(e) => handleItemChange(index, 'name', e.target.value)}
                                        >
                                            <option value="">Enter Item name</option>
                                            {products.map(p => (
                                                <option key={p._id} value={p.name}>{p.name} (Stock: {p.quantity})</option>
                                            ))}
                                        </select>
                                    </td>
                                    <td>
                                        <input 
                                            type="number"
                                            className="ss-billing-item-input"
                                            value={item.quantity}
                                            placeholder="0"
                                            onChange={(e) => handleItemChange(index, 'quantity', e.target.value)}
                                        />
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                                            <span style={{ color: 'var(--text-muted)', fontSize: '12px' }}>Rs.</span>
                                            <input 
                                                type="number"
                                                className="ss-billing-item-input"
                                                value={item.rate}
                                                placeholder="0"
                                                onChange={(e) => handleItemChange(index, 'rate', e.target.value)}
                                            />
                                        </div>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '2px', background: 'var(--hover)', padding: '2px 6px', borderRadius: '6px' }}>
                                                <input 
                                                    type="number"
                                                    style={{ width: '30px', border: 'none', background: 'transparent', fontSize: '12px', textAlign: 'center', outline: 'none' }}
                                                    value={item.discountPercent}
                                                    placeholder="0"
                                                    onChange={(e) => handleItemChange(index, 'discountPercent', e.target.value)}
                                                />
                                                <span style={{ fontSize: '10px', fontWeight: 800, color: 'var(--text-muted)' }}>%</span>
                                            </div>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                                                <span style={{ color: 'var(--text-muted)', fontSize: '12px' }}>Rs.</span>
                                                <input 
                                                    type="number"
                                                    className="ss-billing-item-input"
                                                    value={item.discountAmount}
                                                    placeholder="0"
                                                    onChange={(e) => handleItemChange(index, 'discountAmount', e.target.value)}
                                                />
                                            </div>
                                        </div>
                                    </td>
                                    <td style={{ fontWeight: 700, color: 'var(--text-primary)' }}>
                                        Rs. {item.amount.toFixed(2)}
                                    </td>
                                    <td>
                                        <button onClick={() => handleRemoveItem(index)} style={{ border: 'none', background: 'transparent', color: 'var(--text-muted)', cursor: 'pointer' }}>
                                            {Icon.trash}
                                        </button>
                                    </td>
                                </tr>
                            ))}
                            <tr style={{ background: 'var(--table-head)' }}>
                                <td colSpan="3">
                                    <button onClick={handleAddItem} style={{ display: 'flex', alignItems: 'center', gap: '6px', border: 'none', background: 'transparent', color: 'var(--pos)', fontWeight: 700, fontSize: '13px' }}>
                                        {Icon.plus} Add Billing Item
                                    </button>
                                </td>
                                <td style={{ fontSize: '11px', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>Sub Total</td>
                                <td colSpan="3" style={{ fontWeight: 800, color: 'var(--text-primary)', textAlign: 'right', paddingRight: '40px' }}>
                                    Rs. {subTotal.toFixed(2)}
                                </td>
                            </tr>
                        </tbody>
                    </table>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: '40px' }}>
                    <div>
                        <label style={{ display: 'block', fontSize: '11px', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '8px' }}>Notes or Remarks</label>
                        <textarea 
                            className="ss-invoice-input"
                            style={{ height: '100px', resize: 'none' }}
                            placeholder="Enter note or description..."
                            value={notes}
                            onChange={(e) => setNotes(e.target.value)}
                        />
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px', paddingTop: '8px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                            <label style={{ fontSize: '11px', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>Total Amount</label>
                            <div style={{ background: 'var(--input-bg)', border: '1px solid var(--border)', borderRadius: '12px', padding: '12px 20px', width: '220px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                <span style={{ color: 'var(--text-muted)', fontWeight: 600 }}>Rs.</span>
                                <span style={{ fontSize: '20px', fontWeight: 800, color: 'var(--text-primary)' }}>{totalAmount.toFixed(2)}</span>
                            </div>
                        </div>

                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                            <label style={{ fontSize: '11px', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>Payment Mode</label>
                            <select 
                                className="ss-invoice-select"
                                style={{ width: '220px' }}
                                value={paymentMode}
                                onChange={(e) => setPaymentMode(e.target.value)}
                            >
                                <option>Cash</option>
                                <option>Cheque</option>
                                <option>Online</option>
                            </select>
                        </div>
                    </div>
                </div>

                <div className="ss-invoice-footer">
                    <button className="ss-btn-save-new" onClick={() => handleSaveInvoice(true)}>
                        Save & New
                    </button>
                    <button className="ss-btn-save" onClick={() => handleSaveInvoice(false)}>
                        Save Sales Invoice
                    </button>
        </div>
        <ToastContainer />
      </div>
    </div>
  </div>
</div>
  );
}

export default SalesInvoice;

import React, { useState, useEffect } from 'react'

import { handleError, handleSuccess } from '../utils'
import { ToastContainer } from 'react-toastify'
import '../styles/Settings.css'

import Sidebar from '../components/common/Sidebar';
import Topbar from '../components/common/Topbar';
import Icon from '../components/common/Icons';

function Settings({ theme, onToggleTheme }) {

    const [activeTab, setActiveTab] = useState('general')
    const [user, setUser] = useState({ name: '', businessName: '', email: '' })
    const [passwords, setPasswords] = useState({ oldPassword: '', newPassword: '', confirmPassword: '' })


    async function fetchUserProfile() {
        try {
            const response = await fetch('http://localhost:8000/users/profile', {
                headers: { 'Authorization': localStorage.getItem('token') }
            })
            const result = await response.json()
            if (result.success) {
                setUser(result.user)
            }
        } catch {
            handleError("Failed to fetch profile")
        }
    }

    useEffect(() => {
        fetchUserProfile()
    }, [])

    const handleUpdateProfile = async (e) => {
        e.preventDefault()
        try {
            const response = await fetch('http://localhost:8000/users/update-profile', {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': localStorage.getItem('token')
                },
                body: JSON.stringify({ name: user.name, businessName: user.businessName })
            })
            const result = await response.json()
            if (result.success) {
                handleSuccess(result.message)
                localStorage.setItem('loggedInUser', user.name)
                localStorage.setItem('businessName', user.businessName)
            } else {
                handleError(result.message)
            }
        } catch {
            handleError("Update failed")
        }
    }

    const handleUpdatePassword = async (e) => {
        e.preventDefault()
        if (passwords.newPassword !== passwords.confirmPassword) {
            return handleError("Passwords do not match")
        }
        try {
            const response = await fetch('http://localhost:8000/users/update-password', {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': localStorage.getItem('token')
                },
                body: JSON.stringify({ oldPassword: passwords.oldPassword, newPassword: passwords.newPassword })
            })
            const result = await response.json()
            if (result.success) {
                handleSuccess(result.message)
                setPasswords({ oldPassword: '', newPassword: '', confirmPassword: '' })
            } else {
                handleError(result.message)
            }
        } catch {
            handleError("Password update failed")
        }
    }


    const tabs = [
        { id: 'general', label: 'General', icon: Icon.settings },
        { id: 'account', label: 'My Account', icon: Icon.user },
        { id: 'business', label: 'Business Profile', icon: Icon.briefcase },
    ]

    return (
        <div className="ss-layout">
            <Sidebar activeSection="settings" />

            <div className="ss-main">
                <Topbar 
                    title="Settings" 
                    onToggleTheme={onToggleTheme}
                    isDark={theme === 'dark'}
                />

                <div className="ss-content">
                    <div className="settings-container">
                        <aside className="settings-nav">
                            <div className="settings-nav-header">Settings</div>
                            <div className="settings-nav-items">
                                {tabs.map(tab => (
                                    <button
                                        key={tab.id}
                                        className={`settings-nav-button ${activeTab === tab.id ? 'active' : ''}`}
                                        onClick={() => setActiveTab(tab.id)}
                                    >
                                        <span className="nav-button-icon">{tab.icon}</span>
                                        <span className="nav-button-label">{tab.label}</span>
                                    </button>
                                ))}
                            </div>
                        </aside>

                        <main className="settings-view">
                            {activeTab === 'general' && (
                                <div className="settings-panel animate-slide-up">
                                    <header className="panel-header">
                                        <h2>General Settings</h2>
                                        <p>Personalize your workspace and language preferences.</p>
                                    </header>

                                    <section className="panel-section">
                                        <div className="section-title">Appearance</div>
                                        <div className="theme-grid">
                                            <div 
                                                className={`theme-option ${theme === 'light' ? 'selected' : ''}`}
                                                onClick={() => theme !== 'light' && onToggleTheme()}
                                            >
                                                <div className="theme-preview-box light">
                                                    <div className="preview-indicator"></div>
                                                </div>
                                                <div className="theme-label">Light Mode</div>
                                            </div>
                                            <div 
                                                className={`theme-option ${theme === 'dark' ? 'selected' : ''}`}
                                                onClick={() => theme !== 'dark' && onToggleTheme()}
                                            >
                                                <div className="theme-preview-box dark">
                                                    <div className="preview-indicator"></div>
                                                </div>
                                                <div className="theme-label">Dark Mode</div>
                                            </div>
                                        </div>
                                    </section>

                                    <section className="panel-section">
                                        <div className="section-title">Language</div>
                                        <div className="language-card">
                                            <span className="lang-flag">🇺🇸</span>
                                            <span className="lang-name">English (United States)</span>
                                            <Icon.chevronRight className="lang-chevron" />
                                        </div>
                                    </section>
                                </div>
                            )}

                            {activeTab === 'account' && (
                                <div className="settings-panel animate-slide-up">
                                    <header className="panel-header">
                                        <h2>Account Settings</h2>
                                        <p>Manage your personal information and security.</p>
                                    </header>

                                    <section className="panel-section">
                                        <div className="section-title">Profile Information</div>
                                        <form onSubmit={handleUpdateProfile} className="settings-form">
                                            <div className="ss-form-group">
                                                <label className="ss-form-label">Full Name</label>
                                                <input 
                                                    type="text" 
                                                    className="ss-form-input"
                                                    value={user.name}
                                                    onChange={(e) => setUser({ ...user, name: e.target.value })}
                                                    placeholder="Your name"
                                                />
                                            </div>
                                            <div className="ss-form-group">
                                                <label className="ss-form-label">Email Address</label>
                                                <input type="email" className="ss-form-input readonly" value={user.email} disabled />
                                                <p className="field-hint">Your email is used for login and cannot be changed.</p>
                                            </div>
                                            <button type="submit" className="ss-btn-success">Save Changes</button>
                                        </form>
                                    </section>

                                    <section className="panel-section">
                                        <div className="section-title">Security</div>
                                        <form onSubmit={handleUpdatePassword} className="settings-form">
                                            <div className="ss-form-group">
                                                <label className="ss-form-label">Old Password</label>
                                                <input 
                                                    type="password" 
                                                    className="ss-form-input"
                                                    value={passwords.oldPassword}
                                                    onChange={(e) => setPasswords({ ...passwords, oldPassword: e.target.value })}
                                                    placeholder="••••••••"
                                                />
                                            </div>
                                            <div className="grid-2">
                                                <div className="ss-form-group">
                                                    <label className="ss-form-label">New Password</label>
                                                    <input 
                                                        type="password" 
                                                        className="ss-form-input"
                                                        value={passwords.newPassword}
                                                        onChange={(e) => setPasswords({ ...passwords, newPassword: e.target.value })}
                                                        placeholder="••••••••"
                                                    />
                                                </div>
                                                <div className="ss-form-group">
                                                    <label className="ss-form-label">Confirm Password</label>
                                                    <input 
                                                        type="password" 
                                                        className="ss-form-input"
                                                        value={passwords.confirmPassword}
                                                        onChange={(e) => setPasswords({ ...passwords, confirmPassword: e.target.value })}
                                                        placeholder="••••••••"
                                                    />
                                                </div>
                                            </div>
                                            <button type="submit" className="ss-btn-save-new">Update Password</button>
                                        </form>
                                    </section>
                                </div>
                            )}

                            {activeTab === 'business' && (
                                <div className="settings-panel animate-slide-up">
                                    <header className="panel-header">
                                        <h2>Business Profile</h2>
                                        <p>Customize how your business appears on invoices.</p>
                                    </header>

                                    <section className="panel-section">
                                        <div className="section-title">Business Identity</div>
                                        <form onSubmit={handleUpdateProfile} className="settings-form">
                                            <div className="ss-form-group">
                                                <label className="ss-form-label">Business Name</label>
                                                <input 
                                                    type="text" 
                                                    className="ss-form-input"
                                                    value={user.businessName}
                                                    onChange={(e) => setUser({ ...user, businessName: e.target.value })}
                                                    placeholder="SmartStock Inc."
                                                />
                                            </div>
                                            <div className="ss-form-group">
                                                <label className="ss-form-label">Registered Address</label>
                                                <input type="text" className="ss-form-input readonly" placeholder="Lalitpur, Nepal" disabled />
                                            </div>
                                            <button type="submit" className="ss-btn-success">Save Business Details</button>
                                        </form>
                                    </section>
                                </div>
                            )}
                        </main>
                    </div>
                </div>
                <ToastContainer />
            </div>
        </div>
    );
}

export default Settings;
